/**
 * Telegram Mini App (TMA) Integration Service
 * Strictly restricted to identity lookup per privacy policy.
 */

export interface TelegramUser {
  id: number;
  username?: string;
  first_name?: string;
  last_name?: string;
  language_code?: string;
  is_premium?: boolean;
}

export const getTelegramWebApp = () => {
  if (typeof window === 'undefined') return null;
  return (window as any).Telegram?.WebApp;
};

export const isTelegramEnvironment = () => {
  const tg = getTelegramWebApp();
  // Ensure tg is actually populated; some iOS webviews might have the object but not the data yet
  return !!(tg && tg.initData && tg.initData.length > 0);
};

/**
 * Returns the full Telegram User object if available.
 */
export const getTelegramUser = (): TelegramUser | null => {
  const tg = getTelegramWebApp();
  if (!tg) return null;
  return tg.initDataUnsafe?.user || null;
};

/**
 * Returns ONLY the telegram_id. 
 */
export const getTelegramUserId = (): number | null => {
  return getTelegramUser()?.id || null;
};

export const initTelegramTheme = () => {
  const tg = getTelegramWebApp();
  if (!tg) return;

  try {
    tg.ready();
    tg.expand();

    if (tg.setHeaderColor) tg.setHeaderColor('#fcfcfb');
    if (tg.setBackgroundColor) tg.setBackgroundColor('#fcfcfb');
  } catch (e) {
    console.warn("TMA Theme init failed", e);
  }
};

export const triggerHaptic = (style: 'light' | 'medium' | 'heavy' | 'success' | 'warning' | 'error' = 'light') => {
  const tg = getTelegramWebApp();
  if (!tg?.HapticFeedback) return;

  try {
    if (['success', 'warning', 'error'].includes(style)) {
      tg.HapticFeedback.notificationOccurred(style as any);
    } else {
      tg.HapticFeedback.impactOccurred(style as any);
    }
  } catch (e) {
    console.debug("Haptic trigger failed", e);
  }
};

export const openTelegramLink = (url: string) => {
  const tg = getTelegramWebApp();
  if (tg && tg.openTelegramLink) {
    tg.openTelegramLink(url);
  } else {
    window.open(url, '_blank');
  }
};

import { GoogleGenAI, Modality } from "@google/genai";
import { Language } from "../types";
import { VOICE_MAPPING } from "../constants";

const audioBufferCache = new Map<string, AudioBuffer>();
let sharedAudioCtx: AudioContext | null = null;

/**
 * Standardizes the AudioContext retrieval.
 */
export function getAudioContext() {
  if (!sharedAudioCtx) {
    const AudioContextClass = (window as any).AudioContext || (window as any).webkitAudioContext;
    sharedAudioCtx = new AudioContextClass({ sampleRate: 24000 });
  }
  return sharedAudioCtx;
}

/**
 * Robustly resumes the AudioContext within a user gesture.
 * Includes a "Silent Ping" to wake up iOS hardware.
 */
export async function resumeAudioContext(): Promise<void> {
  const ctx = getAudioContext();

  if (ctx.state !== 'running') {
    try {
      await ctx.resume();

      // Critical iOS Fix: Inject a tiny silent buffer to "warm" the audio hardware.
      const buffer = ctx.createBuffer(1, 1, 24000);
      const source = ctx.createBufferSource();
      source.buffer = buffer;
      source.connect(ctx.destination);
      source.start(0);

      console.debug("Philologist Voice Engine: iOS Audio Hardware Primed.");
    } catch (e) {
      console.warn("Philologist Voice Engine: Audio Context blocked by system:", e);
    }
  }
}

/**
 * Custom base64 decoder.
 */
function decode(base64: string): Uint8Array {
  const binaryString = atob(base64);
  const bytes = new Uint8Array(binaryString.length);
  for (let i = 0; i < binaryString.length; i++) {
    bytes[i] = binaryString.charCodeAt(i);
  }
  return bytes;
}

/**
 * Decodes raw PCM 16-bit audio bytes into an AudioBuffer.
 */
async function decodeAudioData(
  data: Uint8Array,
  ctx: AudioContext,
  sampleRate: number,
  numChannels: number,
): Promise<AudioBuffer> {
  const arrayBuffer = data.buffer.slice(data.byteOffset, data.byteOffset + data.byteLength);
  const dataInt16 = new Int16Array(arrayBuffer);

  const frameCount = dataInt16.length / numChannels;
  const buffer = ctx.createBuffer(numChannels, frameCount, sampleRate);

  for (let channel = 0; channel < numChannels; channel++) {
    const channelData = buffer.getChannelData(channel);
    for (let i = 0; i < frameCount; i++) {
      channelData[i] = dataInt16[i * numChannels + channel] / 32768.0;
    }
  }
  return buffer;
}

/**
 * Synthesizes and plays text via Gemini TTS.
 */
export async function speak(text: string, lang: Language): Promise<void> {
  if (!text || !text.trim()) return;

  try {
    await resumeAudioContext();

    const cacheKey = `${text.trim()}-${lang}`;
    const audioCtx = getAudioContext();

    const playBuffer = (buffer: AudioBuffer) => {
      if (audioCtx.state !== 'running') {
        audioCtx.resume().then(() => {
          const source = audioCtx.createBufferSource();
          source.buffer = buffer;
          source.connect(audioCtx.destination);
          source.start(0);
        });
      } else {
        const source = audioCtx.createBufferSource();
        source.buffer = buffer;
        source.connect(audioCtx.destination);
        source.start(0);
      }
    };

    if (audioBufferCache.has(cacheKey)) {
      playBuffer(audioBufferCache.get(cacheKey)!);
      return;
    }

    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
    const voiceName = VOICE_MAPPING[lang] || 'Puck';

    const response = await ai.models.generateContent({
      model: "gemini-2.5-flash-preview-tts",
      contents: [{ parts: [{ text: `Say clearly: ${text}` }] }],
      config: {
        responseModalities: [Modality.AUDIO],
        speechConfig: {
          voiceConfig: {
            prebuiltVoiceConfig: { voiceName },
          },
        },
      },
    });

    const base64Audio = response.candidates?.[0]?.content?.parts?.[0]?.inlineData?.data;
    if (!base64Audio) return;

    const audioBuffer = await decodeAudioData(decode(base64Audio), audioCtx, 24000, 1);
    audioBufferCache.set(cacheKey, audioBuffer);
    playBuffer(audioBuffer);
  } catch (error) {
    console.error("Philologist Voice Engine Failure:", error);
    // Do not throw; we want to preserve the caller's execution flow (like search)
  }
}
